import{_ as t,a,b as o,c as l}from"./chunks/授权完复制token.D-mju0qq.js";import{_ as i,o as d,c as r,a2 as n}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Google Drive チャンネルの追加","description":"","frontmatter":{},"headers":[],"relativePath":"ja-JP/upload/google-drive.md","filePath":"ja-JP/upload/google-drive.md","lastUpdated":1781962217000}'),h={name:"ja-JP/upload/google-drive.md"};function s(c,e,g,p,u,m){return d(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="google-drive-チャンネルの追加" tabindex="-1">Google Drive チャンネルの追加 <a class="header-anchor" href="#google-drive-チャンネルの追加" aria-label="Permalink to &quot;Google Drive チャンネルの追加&quot;">​</a></h1><p>Google Drive チャンネルは、Google Drive を ImgBed の保存先として利用します。</p><h2 id="事前に用意するもの" tabindex="-1">事前に用意するもの <a class="header-anchor" href="#事前に用意するもの" aria-label="Permalink to &quot;事前に用意するもの&quot;">​</a></h2><table tabindex="0"><thead><tr><th>必要なもの</th><th>用途</th></tr></thead><tbody><tr><td>Google アカウント</td><td>Drive と OAuth アプリを管理します</td></tr><tr><td>Google Cloud プロジェクト</td><td>OAuth Client を作成します</td></tr><tr><td>Client ID / Client Secret</td><td>ImgBed から Google Drive を操作するため</td></tr><tr><td>Refresh Token</td><td>長期的なアクセスに使います</td></tr><tr><td>ImgBed ドメイン</td><td>OAuth コールバック URL に使います</td></tr></tbody></table><h2 id="oauth-client-を作成する" tabindex="-1">OAuth Client を作成する <a class="header-anchor" href="#oauth-client-を作成する" aria-label="Permalink to &quot;OAuth Client を作成する&quot;">​</a></h2><p>Google Cloud Console で OAuth Client を作成します。種類は Web アプリケーションを選びます。</p><p><img src="'+t+'" alt="OAuth Client 作成" loading="lazy"></p><p>承認済みのリダイレクト URI に次を設定します。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://あなたのドメイン/api/oauth/google/callback</span></span></code></pre></div><p><img src="'+a+'" alt="OAuth URL 設定" loading="lazy"></p><h2 id="imgbed-へ入力する" tabindex="-1">ImgBed へ入力する <a class="header-anchor" href="#imgbed-へ入力する" aria-label="Permalink to &quot;ImgBed へ入力する&quot;">​</a></h2><p>アップロード設定で <code>Google Drive</code> を選び、まず Client ID と Client Secret を入力します。</p><p><img src="'+o+'" alt="Google Drive 設定" loading="lazy"></p><table tabindex="0"><thead><tr><th>項目</th><th>入力内容</th></tr></thead><tbody><tr><td>チャンネル名</td><td>例：<code>Google Drive Main</code></td></tr><tr><td>Client ID</td><td>Google Cloud で作成した OAuth Client ID</td></tr><tr><td>Client Secret</td><td>OAuth Client Secret</td></tr><tr><td>Refresh Token</td><td>後で取得して貼り付けます</td></tr><tr><td>ルートディレクトリ</td><td>任意。通常は <code>imgbed</code></td></tr></tbody></table><h2 id="refresh-token-を取得する" tabindex="-1">Refresh Token を取得する <a class="header-anchor" href="#refresh-token-を取得する" aria-label="Permalink to &quot;Refresh Token を取得する&quot;">​</a></h2><ol><li>ImgBed で「Token を取得」をクリックします。</li><li>保存先に使う Google アカウントでログインします。</li><li>権限を許可します。</li><li>コールバックページに表示された Refresh Token をコピーします。</li><li>ImgBed の <code>Refresh Token</code> 欄へ貼り付けます。</li></ol><p><img src="'+l+'" alt="Refresh Token コピー" loading="lazy"></p><h2 id="保存後の確認" tabindex="-1">保存後の確認 <a class="header-anchor" href="#保存後の確認" aria-label="Permalink to &quot;保存後の確認&quot;">​</a></h2><ol><li>チャンネルを保存します。</li><li>テスト画像をアップロードします。</li><li>Google Drive の指定ディレクトリにファイルが作成されることを確認します。</li><li>返されたリンクが開けることを確認します。</li></ol><h2 id="注意点" tabindex="-1">注意点 <a class="header-anchor" href="#注意点" aria-label="Permalink to &quot;注意点&quot;">​</a></h2><ul><li>Google Cloud の OAuth 同意画面設定が未完了だと認証できない場合があります。</li><li>Refresh Token を取得した Google アカウントが、実際の保存先になります。</li><li>Drive 容量が不足しているとアップロードに失敗します。</li><li>OAuth Client Secret を公開しないでください。</li></ul>',21)])])}const v=i(h,[["render",s]]);export{f as __pageData,v as default};
